public class PrimitiveType {
    public void downCastPrimitiveType(int i) {
        try {
            System.out.println(" i [" + i + "]");
        } catch(NullPointerException e) {
            e.printStackTrace();
        } catch(RuntimeException e) {
            e.printStackTrace();
        } catch(Exception e) {
            e.printStackTrace();
        }
    }
}
